// Validate incoming booking data
const body = $input.first().json.body;

const required = ['patientName', 'patientPhone', 'date', 'startTime'];
const missing = required.filter(field => !body[field]);

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      error: `Липсващи полета: ${missing.join(', ')}`
    }
  }];
}

// Validate phone number (Bulgarian format)
const phone = body.patientPhone.replace(/\s/g, '');
const phoneRegex = /^(\+359|0)[0-9]{9}$/;
if (!phoneRegex.test(phone)) {
  return [{
    json: {
      valid: false,
      error: 'Невалиден телефонен номер. Моля, използвайте формат: 0888123456 или +359888123456'
    }
  }];
}

// Validate notification channels — only sms + email supported now
const allowedChannels = ['sms', 'email'];
let notify = Array.isArray(body.notify) ? body.notify : [];
notify = notify.filter(c => allowedChannels.includes(c));
if (notify.length === 0) {
  // Backward compat: default to SMS if nothing was sent
  notify = ['sms'];
}

// If email channel selected, email must be a valid address
const patientEmail = (body.patientEmail || '').trim();
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (notify.includes('email')) {
  if (!patientEmail || !emailRegex.test(patientEmail)) {
    return [{
      json: {
        valid: false,
        error: 'За имейл известия е нужен валиден имейл адрес'
      }
    }];
  }
}

// Validate date is in the future
const bookingDate = new Date(body.date + 'T' + body.startTime);
const now = new Date();
if (bookingDate < now) {
  return [{
    json: {
      valid: false,
      error: 'Не може да запазите час в миналото'
    }
  }];
}

// Limit public booking window: maximum 1 calendar month ahead
const today = new Date();
today.setHours(0, 0, 0, 0);
const maxBookingDate = new Date(today.getFullYear(), today.getMonth() + 1, today.getDate(), 23, 59, 59);
if (bookingDate > maxBookingDate) {
  return [{
    json: {
      valid: false,
      error: 'Часове могат да се запазват максимум 1 месец напред'
    }
  }];
}

// Check if it's a working day
const dayOfWeek = new Date(body.date).getDay();
if (dayOfWeek === 0 || dayOfWeek === 6) {
  return [{
    json: {
      valid: false,
      error: 'Събота и неделя са почивни дни'
    }
  }];
}

// Default duration is 30 minutes for new bookings
const duration = 30;

return [{
  json: {
    valid: true,
    patientName: body.patientName.trim(),
    patientPhone: phone,
    patientEmail: patientEmail,
    notify: notify,
    date: body.date,
    startTime: body.startTime,
    duration: duration,
    reason: (body.reason || '').trim(),
    notes: (body.notes || '').trim()
  }
}];

// Get the booking request
const booking = $('Validate Input').first().json;
const bookingDate = booking.date;
const bookingTime = booking.startTime;

// Helper function to convert to Europe/Sofia timezone and get minutes
function toSofiaMinutes(isoString) {
  if (!isoString) return null;
  const d = new Date(isoString);
  const options = {
    timeZone: 'Europe/Sofia',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  };
  const formatter = new Intl.DateTimeFormat('en-CA', options);
  const parts = formatter.formatToParts(d);
  const hour = parseInt(parts.find(p => p.type === 'hour')?.value || '0');
  const minute = parseInt(parts.find(p => p.type === 'minute')?.value || '0');
  return hour * 60 + minute;
}

function timeToMinutes(time) {
  const [hours, minutes] = time.split(':').map(Number);
  return hours * 60 + minutes;
}

const bookingStart = timeToMinutes(bookingTime);

// Get existing calendar events from Get Calendar Events node
const calendarEvents = $('Get Calendar Events').all();

// Check for exact same start time AND calculate max available minutes
let hasExactConflict = false;
let conflictWith = null;
let nextEventStart = 18 * 60; // Default: end of working day (18:00)

for (const item of calendarEvents) {
  const event = item.json;

  // Skip cancelled events
  if (event.status === 'cancelled') continue;

  let existingStart = null;

  if (event.start?.dateTime) {
    // CONVERT TO SOFIA TIMEZONE
    existingStart = toSofiaMinutes(event.start.dateTime);
  } else if (event.start?.date) {
    // All-day event blocks entire day
    hasExactConflict = true;
    conflictWith = 'целодневно събитие';
    break;
  }

  if (existingStart === null) continue;

  // Check for exact same start time
  if (bookingStart === existingStart) {
    hasExactConflict = true;
    const startHour = Math.floor(existingStart / 60);
    const startMin = existingStart % 60;
    conflictWith = `${startHour.toString().padStart(2, '0')}:${startMin.toString().padStart(2, '0')}`;
    break;
  }

  // Find the earliest event that starts AFTER our booking start time
  if (existingStart > bookingStart && existingStart < nextEventStart) {
    nextEventStart = existingStart;
  }
}

if (hasExactConflict) {
  return [{
    json: {
      conflict: true,
      error: `Този час (${bookingTime}) вече е зает. Моля изберете друг час.`
    }
  }];
}

// Calculate max available minutes until next event
const maxAvailableMinutes = nextEventStart - bookingStart;

// Determine which buttons to show
const can30 = maxAvailableMinutes >= 30;
const can60 = maxAvailableMinutes >= 60;

const id = 'apt_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 8);

return [{
  json: {
    conflict: false,
    id: id,
    patientName: booking.patientName,
    patientPhone: booking.patientPhone,
    patientEmail: booking.patientEmail,
    notify: booking.notify,
    date: booking.date,
    startTime: booking.startTime,
    duration: booking.duration,
    reason: booking.reason,
    notes: booking.notes,
    maxAvailableMinutes: maxAvailableMinutes,
    can30: can30,
    can60: can60
  }
}];

// Prepare calendar event data
// IMPORTANT: This node now runs AFTER "Save Patient to Sheet" so we know if the patient is new.
const booking = $('Check Conflict').first().json;

// Determine if this is a new patient based on patients-upsert response.
// The upstream "Save Patient to Sheet" returns { success, action: 'created' | 'skipped', ... }.
// `$input.first().json` is that response.
const upsertResp = $input.first().json || {};
const isNewPatient = upsertResp.action === 'created';

// For PUBLIC bookings: new patient -> auto reminder ON, returning patient -> OFF (doctor can flip from admin)
const sendReminder = isNewPatient;

// Calculate end time
const [hours, minutes] = booking.startTime.split(':').map(Number);
const startMinutes = hours * 60 + minutes;
const endMinutes = startMinutes + booking.duration;
const endHours = Math.floor(endMinutes / 60);
const endMins = endMinutes % 60;
const endTime = `${endHours.toString().padStart(2, '0')}:${endMins.toString().padStart(2, '0')}`;

const notifyList = Array.isArray(booking.notify) ? booking.notify : ['sms'];
const notifyLabel = notifyList.map(n => ({
  sms: 'SMS', email: 'Имейл'
}[n] || n)).join(', ');

// Build description with structured data
let description = `📞 Тел: ${booking.patientPhone}\n`;
if (booking.patientEmail) {
  description += `✉️ Имейл: ${booking.patientEmail}\n`;
}
description += `📬 Известия: ${notifyLabel}\n`;
description += `🔔 Напомняне: ${sendReminder ? 'ДА' : 'НЕ'}\n`;
description += `👤 Тип: ${isNewPatient ? 'НОВ пациент' : 'Редовен пациент'}\n`;
if (booking.reason) {
  description += `📋 Причина: ${booking.reason}\n`;
}
if (booking.notes) {
  description += `📝 Бележки: ${booking.notes}\n`;
}
description += `\n⏳ Статус: ЧАКАЩ (pending)\n`;
description += `🆔 ID: ${booking.id}\n`;
description += `📅 Създаден: ${new Date().toLocaleString('bg-BG')}`;

return [{
  json: {
    summary: `⏳ ${booking.patientName}`,
    description: description,
    startDateTime: `${booking.date}T${booking.startTime}:00`,
    endDateTime: `${booking.date}T${endTime}:00`,
    colorId: '5',  // Yellow for pending
    id: booking.id,
    patientName: booking.patientName,
    patientPhone: booking.patientPhone,
    patientEmail: booking.patientEmail || '',
    notify: notifyList,
    isNewPatient: isNewPatient,
    sendReminder: sendReminder
  }
}];

// Prepare success response
const calendarEvent = $input.first().json;
const preparedData = $('Prepare Event Data').first().json;

return [{
  json: {
    success: true,
    message: 'Часът е запазен успешно! Очаквайте потвърждение.',
    booking: {
      id: preparedData.id,
      googleEventId: calendarEvent.id,
      patientName: preparedData.patientName,
      patientPhone: preparedData.patientPhone,
      date: preparedData.startDateTime.split('T')[0],
      startTime: preparedData.startDateTime.split('T')[1].slice(0, 5),
      status: 'pending'
    }
  }
}];

